import { useState, useEffect } from "react";

function ViewApplications() {

  const [apps, setApps] = useState([]);

  const loggedUser = JSON.parse(localStorage.getItem("loggedInUser"));

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("applications")) || [];
    setApps(stored);
  }, []);

  const updateStatus = (id, status) => {

    if (loggedUser?.role !== "Admin") return;

    const updated = apps.map(app =>
      app.id === id ? { ...app, status } : app
    );

    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));

    alert(`Application ${status}`);
  };

  const getEmployeeName = (a) => {

    if (a.employee) return a.employee;
    if (a.employeeName) return a.employeeName;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const foundEmp = employees.find(e =>
      e.empId === a.empId ||
      e.id === a.empId ||
      e.email === a.email
    );

    if (foundEmp) return foundEmp.name;

    const users = JSON.parse(localStorage.getItem("users")) || [];
    const foundUser = users.find(u =>
      u.empId === a.empId ||
      u.username === a.email ||
      u.email === a.email
    );

    return foundUser?.name || "Unknown";
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications (Admin)</h2>

      <table className="designation-table">

        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>

          {apps.length === 0 ? (
            <tr>
              <td colSpan="7" style={{ textAlign: "center" }}>
                No Applications Found
              </td>
            </tr>
          ) : (
            apps.map((a, index) => (
              <tr key={a.id}>
                <td>{index + 1}</td>

                <td>{getEmployeeName(a)}</td>

                <td>{a.email || "N/A"}</td>
                <td>{a.jobTitle}</td>

                <td>
                  <span
                    style={{
                      padding: "6px 12px",
                      borderRadius: "6px",
                      fontWeight: "600",
                      color: "white",
                      background:
                        a.status === "Approved"
                          ? "green"
                          : a.status === "Rejected"
                            ? "red"
                            : "#64748b",
                    }}
                  >
                    {a.status}
                  </span>
                </td>

                <td>{a.appliedDate || "--"}</td>

                <td style={{ display: "flex", gap: "12px" }}>

                  {/* SHOW BUTTONS ONLY FOR ADMIN */}
                  {loggedUser?.role === "Admin" && (
                    <>
                      <button
                        style={{
                          background: "#16a34a",
                          color: "white",
                          padding: "6px 14px",
                          borderRadius: "6px",
                          border: "none",
                          cursor: "pointer",
                        }}
                        onClick={() => updateStatus(a.id, "Approved")}
                      >
                        Approve
                      </button>

                      <button
                        style={{
                          background: "#dc2626",
                          color: "white",
                          padding: "6px 14px",
                          borderRadius: "6px",
                          border: "none",
                          cursor: "pointer",
                        }}
                        onClick={() => updateStatus(a.id, "Rejected")}
                      >
                        Reject
                      </button>
                    </>
                  )}

                </td>
              </tr>
            ))
          )}

        </tbody>

      </table>
    </div>
  );
}

export default ViewApplications;
